DROP TABLE IF EXISTS `subscription_plans`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `subscription_plans` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `price_cents` int NOT NULL DEFAULT '0',
  `currency` char(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'TWD',
  `billing_interval` enum('free','month','year') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'free',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `sort_order` int NOT NULL DEFAULT '0',
  `ndnp_period_type` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'M' COMMENT 'D/W/M/Y',
  `ndnp_period_point` tinyint unsigned NOT NULL DEFAULT '1' COMMENT 'M:每月幾號扣款',
  `ndnp_period_times` smallint unsigned NOT NULL DEFAULT '99' COMMENT '總授權期數',
  `ndnp_first_charge_delay_days` smallint unsigned NOT NULL DEFAULT '3' COMMENT '首次扣款：建立訂單日後幾天',
  `quota_max_channels` int unsigned NOT NULL DEFAULT '0' COMMENT '可訂閱頻道數上限',
  `quota_max_videos_per_list` int unsigned NOT NULL DEFAULT '0' COMMENT '待看／已看單邊清單筆數上限',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_subscription_plans_slug` (`slug`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
